@echo off
setlocal enabledelayedexpansion
echo ========================================
echo JUNiO 601 NATIVE UI Build (Verification)
echo ========================================
echo.

:: 1. Intentar localizar CMake automáticamente usando vswhere
set "CMAKE_PATH=cmake"
set "VSWHER_EXE=%ProgramFiles(x86)%\Microsoft Visual Studio\Installer\vswhere.exe"

if exist "%VSWHER_EXE%" (
    for /f "usebackq tokens=*" %%i in (`"%VSWHER_EXE%" -latest -products * -requires Microsoft.VisualStudio.Component.VC.CMake.Project -property installationPath`) do (
        set "VS_PATH=%%i"
        set "POTENTIAL_CMAKE=!VS_PATH!\Common7\IDE\CommonExtensions\Microsoft\CMake\CMake\bin\cmake.exe"
        if exist "!POTENTIAL_CMAKE!" (
            set "CMAKE_PATH=!POTENTIAL_CMAKE!"
            echo [INFO] CMake localizado en: !CMAKE_PATH!
        )
    )
)

:: 2. Verificar si cmake es ejecutable
"%CMAKE_PATH%" --version >nul 2>&1
if %ERRORLEVEL% NEQ 0 (
    echo [ERROR] No se pudo encontrar CMake.
    exit /b 1
)

:: 3. Incrementar versión de Build (Compartida)
set "VERSION_FILE=build_no.txt"
if not exist %VERSION_FILE% echo 0 > %VERSION_FILE%
set /p build_no=<%VERSION_FILE%
set /a build_no=%build_no% + 1
echo %build_no% > %VERSION_FILE%

echo #define JUNO_BUILD_VERSION "%build_no%" > "Source/Core/BuildVersion.h"
echo #define JUNO_BUILD_TIMESTAMP "%DATE% %TIME%" >> "Source/Core/BuildVersion.h"

:: 4. Configurar y Compilar (Con Flag de Native UI)
set BUILD_DIR=build_native
if not exist %BUILD_DIR% mkdir %BUILD_DIR%

echo.
echo 1. Configurando proyecto (Native UI)...
"%CMAKE_PATH%" -B %BUILD_DIR% -A x64 -DCMAKE_POLICY_VERSION_MINIMUM=3.5 -DBUILD_SHARED_LIBS=OFF -DUSE_NATIVE_UI=ON
if %ERRORLEVEL% NEQ 0 (
    echo [ERROR] Error en la configuracion de CMake.
    exit /b %ERRORLEVEL%
)

echo.
echo 2. Compilando JUNiO 601 Native (Release)...
"%CMAKE_PATH%" --build %BUILD_DIR% --config Release --target ABDSimpleJuno106_Standalone
if %ERRORLEVEL% NEQ 0 (
    echo [ERROR] La compilacion ha fallado.
    exit /b %ERRORLEVEL%
)

:: 5. Mover ejecutable
echo.
echo 3. Finalizando...
set EXE_SRC=%BUILD_DIR%\ABDSimpleJuno106_artefacts\Release\Standalone\ABDSimpleJuno106.exe
if not exist "%EXE_SRC%" set EXE_SRC=%BUILD_DIR%\Release\ABDSimpleJuno106.exe

if exist "%EXE_SRC%" (
    copy /Y "%EXE_SRC%" "JUNiO_601_Native.exe" >nul
    echo.
    echo ========================================
    echo BUILD NATIVA EXITOSA! (Build #%build_no%)
    echo Ejecutable: JUNiO_601_Native.exe
    echo ========================================
) else (
    echo [ADVERTENCIA] No se encontro el .exe compilado, revisa la carpeta build_native.
)

param(
    [string[]]$Exclude = @(),   # carpetas/rutas adicionales a excluir (relativas al root)
    [switch]$Compact            # modo compacto
)

# Script to bundle all source code into a JSONL file + metadata
# Usage examples:
#   .\bundle_code_jsonl.ps1
#   .\bundle_code_jsonl.ps1 -Exclude "tests","playground"
#   .\bundle_code_jsonl.ps1 -Compact
#   .\bundle_code_jsonl.ps1 -Exclude "tests","src/legacy" -Compact

# Determine root directory based on script location (now in scripts/)
$scriptDir = $PSScriptRoot
$rootDir = (Get-Item $scriptDir).Parent.FullName

$timestamp = Get-Date -Format "yyyyMMddHHmm"

# Ensure exports directory exists
$exportsDir = Join-Path $rootDir "exports"
if (-not (Test-Path $exportsDir)) {
    New-Item -ItemType Directory -Path $exportsDir | Out-Null
}

$jsonlFile   = Join-Path $exportsDir "project_bundle_$timestamp.jsonl"
$metaFile    = Join-Path $exportsDir "project_metadata_$timestamp.json"
$controlFile = Join-Path $exportsDir "CONTROL_FILESCODE_$timestamp.txt"

# Extensions to include
$includeExtensions = @(".h", ".cpp", ".c", ".hpp", ".js", ".css", ".json", ".md", ".ps1", ".bat", ".yml", ".yaml", ".html")
$specificFiles = @(
    "CMakeLists.txt",
    "build_auto.bat",
    "build_no.txt",
    "README.md",
    ".gitignore"
)

# Folders to explicitly INCLUDE (relative to root)
$foldersToProcess = @("Source", "WebUI", "scripts")

# Directories to exclude (always ignore these)
$excludeDirsBase = @(
    "node_modules", ".next", ".git", ".vscode", "tmp", "out", "bin", "obj",
    "public", ".swc", "coverage", "test-results", "secretos", ".turbo",
    ".vercel", "dist", "build", ".contentlayer", ".pnpm-store",
    ".pnpm-debug", ".idea", "temp_migration_data", "JUCE", "logs", "docs"
)

# Combine base excludes with user-provided ones (normalized as paths starting from root)
$excludeDirs = New-Object System.Collections.Generic.List[string]
$excludeDirs.AddRange($excludeDirsBase)

foreach ($ex in $Exclude) {
    if ([string]::IsNullOrWhiteSpace($ex)) { continue }
    # Guardamos tal cual (nombre carpeta o ruta relativa)
    $excludeDirs.Add($ex.Trim())
}

# Files considered "heavy" for Compact mode (by name)
$heavyFilesByName = @(
    "pnpm-lock.yaml",
    "package-lock.json",
    "yarn.lock"
)

# Size threshold in bytes for "heavy" files in Compact mode (5 MB)
$compactSizeThresholdBytes = 5MB

Write-Host "Bundling code from $rootDir to $jsonlFile..."
Write-Host "Metadata file: $metaFile"
Write-Host "Control file:  $controlFile"
Write-Host "Compact mode:  $Compact"
if ($Exclude.Count -gt 0) {
    Write-Host "Additional excludes: $($Exclude -join ', ')"
}

# Helpers
function Get-LanguageFromExtension {
    param(
        [string]$Extension
    )

    switch ($Extension.ToLower()) {
        ".h"    { "cpp" }
        ".hpp"  { "cpp" }
        ".cpp"  { "cpp" }
        ".c"    { "c" }
        ".html" { "html" }
        ".js"   { "javascript" }
        ".css"  { "css" }
        ".json" { "json" }
        ".md"   { "markdown" }
        ".ps1"  { "powershell" }
        ".bat"  { "batch" }
        ".yml"  { "yaml" }
        ".yaml" { "yaml" }
        default { "text" }
    }
}

function Is-InExcludedDir {
    param(
        [string]$RelativePath,
        [System.Collections.Generic.List[string]]$ExcludeList
    )

    foreach ($ex in $ExcludeList) {
        # Normalizamos separadores y comparamos de forma sencilla
        $exNorm = $ex -replace '/', '\'
        if ($RelativePath -like "*\$exNorm\*") { return $true }

        # También contempla casos como ".\ex\..." o "ex\..."
        if ($RelativePath -like ".\$exNorm\*") { return $true }
        if ($RelativePath -like "$exNorm\*") { return $true }
    }

    return $false
}

function Get-ProjectName {
    param(
        [string]$RootDir
    )

    $pkgPath = Join-Path $RootDir "package.json"
    if (Test-Path $pkgPath) {
        try {
            $pkgJson = Get-Content $pkgPath -Raw | ConvertFrom-Json
            if ($pkgJson.name) {
                return $pkgJson.name
            }
        } catch {
            # ignoramos errores y caemos al nombre de carpeta
        }
    }

    return (Split-Path $RootDir -Leaf)
}

function Get-GitInfo {
    param(
        [string]$RootDir
    )

    $gitInfo = [PSCustomObject]@{
        branch = $null
        commit = $null
        dirty  = $null
    }

    try {
        $gitDir = Join-Path $RootDir ".git"
        if (-not (Test-Path $gitDir)) {
            return $gitInfo
        }

        pushd $RootDir | Out-Null

        try {
            $branch = git rev-parse --abbrev-ref HEAD 2>$null
            $commit = git rev-parse HEAD 2>$null
            $status = git status --porcelain 2>$null

            if ($branch) { $gitInfo.branch = $branch.Trim() }
            if ($commit) { $gitInfo.commit = $commit.Trim() }
            if ($status -ne $null) {
                $gitInfo.dirty = -not [string]::IsNullOrWhiteSpace(($status -join "`n"))
            }
        } finally {
            popd | Out-Null
        }
    } catch {
        # Si git falla, dejamos null
    }

    return $gitInfo
}

# Create Writers
$jsonlWriter   = [System.IO.StreamWriter]::new($jsonlFile, $false, [System.Text.Encoding]::UTF8)
$controlWriter = [System.IO.StreamWriter]::new($controlFile, $false, [System.Text.Encoding]::UTF8)

# Global stats
$totalFiles       = 0
$totalBytes       = 0
$includedFiles    = 0
$includedBytes    = 0
$skippedCompact   = 0
$skippedExcluded  = 0
$skippedEmpty     = 0
$skippedErrors    = 0

try {
    # 1. Get files from explicitly included folders
    $allFiles = @()
    foreach ($folder in $foldersToProcess) {
        $folderPath = Join-Path $rootDir $folder
        if (Test-Path $folderPath) {
            $allFiles += Get-ChildItem -Path $folderPath -Recurse -File
        }
    }

    # 2. Get files from root (solo nivel root)
    $rootFiles = Get-ChildItem -Path $rootDir -Depth 0 -File
    $allFiles += $rootFiles

    # Distinct por ruta completa por si acaso
    $allFiles = $allFiles | Sort-Object FullName -Unique

    foreach ($item in $allFiles) {
        $filePath     = $item.FullName
        $relativePath = Resolve-Path -Path $filePath -Relative

        $totalFiles++
        $totalBytes += $item.Length

        # A. Skip by excluded directories
        if (Is-InExcludedDir -RelativePath $relativePath -ExcludeList $excludeDirs) {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_EXCLUDED_DIR")
            continue
        }

        # B. Exclude the output files themselves and junk
        if ($item.Name -like "project_bundle_*") {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_OUTPUT")
            continue
        }
        if ($item.Name -like "CONTROL_FILESCODE_*") {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_OUTPUT")
            continue
        }
        if ($item.Name -like "*.log") {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_LOG")
            continue
        }
        if ($item.Name -like "*.tmp") {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_TMP")
            continue
        }
        if ($item.Name -like "*.bak") {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_BAK")
            continue
        }
        if ($item.Name -eq ".DS_Store") {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_DS_STORE")
            continue
        }
        if ($item.Name -eq "Thumbs.db") {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_THUMBS_DB")
            continue
        }
        if ($item.Name -like ".env*" -and $item.Name -ne ".env.example") {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_ENV")
            continue
        }

        # C. Check extension OR specific filename
        $includeByExt  = $includeExtensions -contains $item.Extension.ToLower()
        $includeByName = $specificFiles -contains $item.Name

        if (-not ($includeByExt -or $includeByName)) {
            $skippedExcluded++
            $controlWriter.WriteLine("$relativePath : SKIPPED_NOT_MATCHING_FILTER")
            continue
        }

        # D. Compact mode: check heavy files
        if ($Compact) {
            $isHeavyByName = $heavyFilesByName -contains $item.Name
            $isHeavyBySize = $item.Length -gt $compactSizeThresholdBytes

            if ($isHeavyByName -or $isHeavyBySize) {
                $skippedCompact++
                $controlWriter.WriteLine("$relativePath : SKIPPED_COMPACT")
                continue
            }
        }

        # E. Read content and write JSONL
        try {
            $content = [System.IO.File]::ReadAllText($filePath)

            if ([string]::IsNullOrWhiteSpace($content)) {
                $skippedEmpty++
                $controlWriter.WriteLine("$relativePath : EMPTY")
                continue
            }

            $language = Get-LanguageFromExtension $item.Extension

            $obj = [PSCustomObject]@{
                type     = "file"
                path     = $relativePath
                language = $language
                size     = $item.Length
                content  = $content
            }

            $json = $obj | ConvertTo-Json -Depth 10 -Compress
            $jsonlWriter.WriteLine($json)

            $includedFiles++
            $includedBytes += $item.Length

            $controlWriter.WriteLine("$relativePath : OK")
            Write-Host "Added: $relativePath"
        }
        catch {
            $skippedErrors++
            $controlWriter.WriteLine("${relativePath} : ERROR $_")
            Write-Error "Failed to process ${relativePath}: $($_)"

        }
    }

    # ---- Global metadata ----
    $projectName = Get-ProjectName -RootDir $rootDir
    $gitInfo     = Get-GitInfo -RootDir $rootDir

    $meta = [PSCustomObject]@{
        projectName = $projectName
        rootDir     = $rootDir
        generatedAt = (Get-Date).ToString("o")
        compactMode = [bool]$Compact
        excludes    = $Exclude
        git         = $gitInfo
        stats       = [PSCustomObject]@{
            totalFiles      = $totalFiles
            totalBytes      = $totalBytes
            includedFiles   = $includedFiles
            includedBytes   = $includedBytes
            skippedExcluded = $skippedExcluded
            skippedCompact  = $skippedCompact
            skippedEmpty    = $skippedEmpty
            skippedErrors   = $skippedErrors
        }
    }

    # 1) Escribir metadata como primer registro del JSONL
    $metaJson = $meta | ConvertTo-Json -Depth 10 -Compress
    # Para asegurarnos de que va al principio, lo escribimos al inicio del archivo.
    # Como ya hemos estado escribiendo, necesitamos regenerar el archivo:
    # Estrategia sencilla: cerrar writer, leer el contenido que acabamos de escribir, reabrir y reordenar.

} finally {
    $jsonlWriter.Close()
    $jsonlWriter.Dispose()

    $controlWriter.Close()
    $controlWriter.Dispose()
}

# Reabrimos JSONL para inyectar la línea meta al principio
# (más simple que intentar "seek" hacia el inicio en StreamWriter).
$existingLines = @()
if (Test-Path $jsonlFile) {
    $existingLines = Get-Content $jsonlFile
}

$metaJson = $meta | ConvertTo-Json -Depth 10 -Compress

# Sobrescribimos el archivo con meta primero y luego el resto
$metaJson | Out-File -FilePath $jsonlFile -Encoding UTF8
if ($existingLines.Count -gt 0) {
    $existingLines | Out-File -FilePath $jsonlFile -Encoding UTF8 -Append
}

# Escribimos metadata en JSON separado
$meta | ConvertTo-Json -Depth 10 | Out-File -FilePath $metaFile -Encoding UTF8

Write-Host "Done!"
Write-Host "JSONL bundle: $jsonlFile"
Write-Host "Metadata:      $metaFile"
Write-Host "Control file:  $controlFile"

#pragma once
#include <JuceHeader.h>
#include <vector>
#include <cmath>

namespace JunoDSP
{
    /**
     * JunoBBD - Authentic MN3009 Bucket Brigade Device Emulation
     * 
     * Features:
     * - Variable Sample Rate Delay Line (Clock-driven)
     * - Compander (NE570 style) integration
     * - Analog Filtering (Anti-aliasing / Reconstruction)
     * - Clock Noise Bleed
     */
    class JunoBBD
    {
    public:
        JunoBBD() {}
        void setMode(int mode) { juce::ignoreUnused(mode); }
        
        void prepare(const juce::dsp::ProcessSpec& spec)
        {
            sampleRate = spec.sampleRate;
            // MN3009 has 256 stages. Max delay ~50ms? 
            // Juno chorus delay is ~11ms-15ms.
            // We need a buffer big enough for lowest clock speed.
            // 20ms at 44.1k = 882 samples.
            // BBD is often modeled as a fractional delay or a ring buffer.
            buffer.setSize(1, (int)(sampleRate * 0.1) + 1); // 100ms safety
            buffer.clear();
            bufferSize = buffer.getNumSamples();
            writePos = 0;
            readPos = 0.0f;
            
            // Filters
            lpFilter.prepare(spec);
            lpFilter.reset(); 
            // MN3009 Reconstruction Filter (approx 10kHz LPF)
            lpFilter.coefficients = juce::dsp::IIR::Coefficients<float>::makeLowPass(sampleRate, 9000.0f);
        }
        
        void reset() {
            buffer.clear();
            writePos = 0;
            readPos = 0.0f;
            currentDelaySamples = 0.0f;
        }
        
        /**
         * Block-processing method (currently unused - PluginProcessor uses processSample()).
         * Preserved for potential future use where block-level dry/wet mixing is needed.
         */
        void process(juce::AudioBuffer<float>& ioBuffer, float delayMs, float mix, float noiseLevel, float clockFreq)
        {
            juce::ignoreUnused(clockFreq);
            const int numSamples = ioBuffer.getNumSamples();
            const float* inData = ioBuffer.getReadPointer(0);
            float* outData = ioBuffer.getWritePointer(0);
            
            // Calculate delay in samples
            float targetDelaySamps = (delayMs * 0.001f) * (float)sampleRate;
            
            for (int i = 0; i < numSamples; ++i)
            {
                float dry = inData[i];
                
                // --- 1. COMPRESSOR (NE570 part 1) ---
                // (Already implemented in PluginProcessor currently, but ideally should be here)
                // We assume input is already compressed/companded if handled externally.
                // For now, we process "dry" as the BBD input.
                
                // Write to BBD (Ring Buffer)
                float* buf = buffer.getWritePointer(0);
                buf[writePos] = dry;
                
                // Read from BBD
                // Cubic interpolation for sound quality
                float actualReadVal = interpolate(targetDelaySamps);
                
                // --- 2. CLOCK NOISE & DEGRADATION ---
                // Add clock whine
                if (noiseLevel > 0.0f) {
                     // Clock bleed artifact
                     // float bleed = std::sin(gui_time * clockFreq ...) 
                     // Simplified: white noise floor
                     actualReadVal += (random.nextFloat() * 2.0f - 1.0f) * noiseLevel;
                }
                
                // --- 3. FILTERING (Reconstruction) ---
                actualReadVal = lpFilter.processSample(actualReadVal);
                
                // Mix
                outData[i] = dry * (1.0f - mix) + actualReadVal * mix;
                
                // Advance pointers
                writePos = (writePos + 1) % bufferSize;
            }
        }
        
        // Per-sample processing optimized for Chorus loop
        float processSample(float input, float delayMs)
        {
             int bufSize = bufferSize; // Local copy
             float* buf = buffer.getWritePointer(0);
             // --- BBD COMPANDER EMULATION (NE570 style soft-clipping) ---
             // Real BBDs saturate non-linearly. This adds the characteristic "warmth".
             float x = input * 1.2f;
             float saturatedInput = std::tanh(x); 
             
             buf[writePos] = saturatedInput;
             
             float delaySamps = (delayMs * 0.001f) * (float)sampleRate;
             float out = interpolate(delaySamps);
             
             writePos++;
             if (writePos >= bufSize) writePos = 0;
             
             // Reconstruction Filter
             return lpFilter.processSample(out);
        }

    private:
        float interpolate(float delaySamples)
        {
            float rPos = (float)writePos - delaySamples;
            while (rPos < 0.0f) rPos += (float)bufferSize;
            while (rPos >= (float)bufferSize) rPos -= (float)bufferSize;
            
            int i1 = (int)rPos;
            int i0 = (i1 - 1 + bufferSize) % bufferSize;
            int i2 = (i1 + 1) % bufferSize;
            int i3 = (i1 + 2) % bufferSize;
            
            float frac = rPos - (float)i1;
            const float* b = buffer.getReadPointer(0);
            
            // Cubic Hermite Interpolation
            float y0 = b[i0], y1 = b[i1], y2 = b[i2], y3 = b[i3];
            float a0 = -0.5f * y0 + 1.5f * y1 - 1.5f * y2 + 0.5f * y3;
            float a1 = y0 - 2.5f * y1 + 2.0f * y2 - 0.5f * y3;
            float a2 = -0.5f * y0 + 0.5f * y2;
            float a3 = y1;
            
            return ((a0 * frac + a1) * frac + a2) * frac + a3;
        }

        juce::AudioBuffer<float> buffer;
        int bufferSize = 0;
        int writePos = 0;
        float readPos = 0.0f;
        float currentDelaySamples = 0.0f;
        double sampleRate = 44100.0;
        
        juce::dsp::IIR::Filter<float> lpFilter;
        juce::Random random;
    };
}

#pragma once
#include <cmath>

/**
 * JunoConstants.h
 * Centralized constants for JUNiO 601 emulations.
 */
namespace JunoConstants
{
    // --- Numerical Helpers ---
    static inline float curveMap(float val, float minV, float maxV) {
        if (minV <= 0.0f) return minV + val * (maxV - minV);
        return minV * std::pow(maxV / minV, val);
    }
    // --- Global DSP Constants ---
    constexpr float kVoiceCrosstalkAmount = 0.007f;
    constexpr float kVoiceOutputGain = 1.5f;
    constexpr float kGlobalThermalDriftScale = 1.5f;
    constexpr float kThermalInertia = 1024; // Samples between drift updates
    constexpr float kThermalMigration = 0.0005f;

    // --- DCO & PWM ---
    constexpr float kDcoDriftMaxSpreadCents = 2.0f;
    constexpr float kDcoDriftMaxGlobalCents = 0.5f;
    constexpr float kDcoDriftMaxVoiceCents = 0.3f;
    constexpr float kMasterClockHz = 8000000.0f;
    constexpr float kDcoMixerSaturationThreshold = 0.6f;
    
    // PWM Constants (Juno-106: 50% center, 95% max)
    constexpr float kPwmCenterDuty = 0.5f;
    constexpr float kPwmMaxDuty = 0.95f;
    constexpr float kPwmMinDuty = 0.05f;
    constexpr float kPwmOffThreshold = 0.98f;
    constexpr float kPwmSlewRateManual = 0.0009f;
    constexpr float kPwmSlewRateLFO = 0.00047f;

    // --- Suboscillator ---
    constexpr float kSubAmpScale = 0.707f; // -3dB

    // --- HPF Constants ---
    namespace HPF
    {
        static constexpr float kFreq2 = 225.0f;
        static constexpr float kFreq3 = 700.0f;
        static constexpr float kShelfFreq = 70.0f;
        static constexpr float kShelfGainDb = 3.0f;
    }

    // --- Voice Kill Thresholds ---
    constexpr float kVoiceKillThreshold = 0.004f; // ~0.4% output level

    // --- Time & Frequency Curves ---
    namespace Curves
    {
        static constexpr float kLfoMinHz = 0.1f;
        static constexpr float kLfoMaxHz = 30.0f;
        static constexpr float kLfoDelayMax = 3.0f; // [Manual] 0-3s
        
        static constexpr float kAttackMin = 0.0015f;
        static constexpr float kAttackMax = 3.0f;
        static constexpr float kDecayMin = 0.0015f;
        static constexpr float kDecayMax = 12.0f;
        static constexpr float kReleaseMin = 0.0015f;
        static constexpr float kReleaseMax = 12.0f;

        static constexpr float kPortamentoMin = 0.005f;
        static constexpr float kPortamentoMax = 2.0f;
    }

    // --- Chorus Constants ---
    namespace Chorus
    {
        static constexpr float kRateI = 0.45f;
        static constexpr float kRateII = 0.8f;
        static constexpr float kDelayBaseMs = 15.0f;
        static constexpr float kModDepthMs = 4.0f;

        static constexpr float kHissLevelHalfDb = -58.0f;
        static constexpr float kHissLevelFullDb = -52.0f;
    }
}

#pragma once

#include <JuceHeader.h>
#include <mutex>

/**
 * JunoLogger
 * 
 * Provides structured logging for the JUNiO 601.
 * Supports categories and severity levels.
 */
namespace JunoLogger {

enum class Level {
    Debug,
    Info,
    Warning,
    Error
};

inline juce::String levelToString(Level level) {
    switch (level) {
        case Level::Debug:   return "DEBUG";
        case Level::Info:    return "INFO";
        case Level::Warning: return "WARNING";
        case Level::Error:   return "ERROR";
    }
    return "UNKNOWN";
}

/**
 * Log a message to the debug output and potentially a file.
 */
inline void log(Level level, const juce::String& category, const juce::String& message) {
    juce::String formattedMessage = juce::String::formatted("[%s] [%s] %s", 
                                    levelToString(level).toRawUTF8(), 
                                    category.toRawUTF8(), 
                                    message.toRawUTF8());
    
    // Always output to debug console
    juce::Logger::writeToLog(formattedMessage);
    
    // [Future] Could also write to a persistent log file here 
    // using a thread-safe mechanism if requested.
}

// Convenience methods
inline void debug(const juce::String& category, const juce::String& message) { log(Level::Debug, category, message); }
inline void info(const juce::String& category, const juce::String& message)  { log(Level::Info, category, message); }
inline void warn(const juce::String& category, const juce::String& message)  { log(Level::Warning, category, message); }
inline void error(const juce::String& category, const juce::String& message) { log(Level::Error, category, message); }

