#pragma once
#include <JuceHeader.h>
#include <vector>

/**
 * JunoSysEx - Helper for Roland Juno-106 SysEx protocol
 * Aligned with Official Roland Specs & junpatch.bas (1994)
 */
namespace JunoSysEx
{
    static constexpr uint8_t kRolandID = 0x41;
    static constexpr uint8_t kMsgPatchDump = 0x30;
    static constexpr uint8_t kMsgManualMode = 0x31;
    static constexpr uint8_t kMsgParamChange = 0x32;

    enum ParamID {
        LFO_RATE = 0x00, LFO_DELAY = 0x01, DCO_LFO = 0x02, DCO_PWM = 0x03,
        DCO_NOISE = 0x04, VCF_FREQ = 0x05, VCF_RES = 0x06, VCF_ENV = 0x07,
        VCF_LFO = 0x08, VCF_KYBD = 0x09, VCA_LEVEL = 0x0A, ENV_A = 0x0B,
        ENV_D = 0x0C, ENV_S = 0x0D, ENV_R = 0x0E, DCO_SUB = 0x0F,
        SWITCHES_1 = 0x10, SWITCHES_2 = 0x11
    };

    /** Individual Parameter Change (0x32) - 7 bytes */
    inline juce::MidiMessage createParamChange(int channel, int paramId, int value)
    {
        uint8_t data[7];
        data[0] = 0xF0;
        data[1] = kRolandID;
        data[2] = kMsgParamChange;
        data[3] = static_cast<uint8_t>(channel & 0x0F);
        data[4] = static_cast<uint8_t>(paramId & 0x7F);
        data[5] = static_cast<uint8_t>(value & 0x7F);
        data[6] = 0xF7;
        return juce::MidiMessage(data, 7);
    }

    /** Manual Mode (0x31) - 6 bytes */
    inline juce::MidiMessage createManualMode(int channel)
    {
        uint8_t data[6];
        data[0] = 0xF0;
        data[1] = kRolandID;
        data[2] = kMsgManualMode;
        data[3] = static_cast<uint8_t>(channel & 0x0F);
        data[4] = 0x00; 
        data[5] = 0xF7;
        return juce::MidiMessage(data, 6);
    }

    static constexpr int kPatchDumpSize = 23;

    /** Patch Dump (0x30) - 23 bytes (F0, 41, 30, Channel, 18-byte Body, F7) */
    inline juce::MidiMessage createPatchDump(int channel, const uint8_t* params16, uint8_t sw1, uint8_t sw2)
    {
        uint8_t data[kPatchDumpSize]; 
        data[0] = 0xF0;
        data[1] = kRolandID;
        data[2] = kMsgPatchDump;
        data[3] = static_cast<uint8_t>(channel & 0x0F);

        memcpy(data + 4, params16, 16);
        data[20] = sw1 & 0x7F;
        data[21] = sw2 & 0x7F;
        data[22] = 0xF7;
        
        return juce::MidiMessage(data, kPatchDumpSize); 
    }

    inline bool parseMessage(const juce::MidiMessage& msg, int& type, int& channel, int& p1, int& p2, uint8_t* dumpBody18Bytes)
    {
        if (!msg.isSysEx()) return false;
        
        const uint8_t* data = msg.getSysExData();
        const int size = msg.getSysExDataSize();
        
        if (size < 2 || data[0] != kRolandID) return false;
        
        type = data[1];
        channel = data[2] & 0x0F;

        if (type == kMsgParamChange && size >= 5) {
             // F0 41 32 ch p v F7 (7 bytes) -> JUCE SysExData size = 5 (41 32 ch p v)
            p1 = data[3] & 0x7F;
            p2 = data[4] & 0x7F;
            return true;
        }
        else if (type == kMsgPatchDump && size >= 21) {
            // F0 41 30 ch [18 bytes] F7 (23 bytes) -> JUCE SysExData size = 21
            if (dumpBody18Bytes) {
                memcpy(dumpBody18Bytes, data + 3, 18);
            }
            return true;
        }
        else if (type == kMsgManualMode && size >= 4) {
             // F0 41 31 ch 00 F7 (6 bytes) -> JUCE SysExData size = 4
             return true;
        }
        return false;
    }

    /**
     * Checks all parameters between 'oldP' and 'newP' and generates SysEx messages
     * for any differences. Handles packed "Switch" bytes efficiently.
     */
    inline void checkSend(const SynthParams& oldP, const SynthParams& newP, int channel, juce::MidiBuffer& buffer, int samplePos)
    {
        // Macros for simple comparisons (7-bit sliders)
        #define CHECK_VAR(param, id, maxVal) \
            if (std::abs(oldP.param - newP.param) > 0.005f) { \
                int v = (int)(newP.param * maxVal); \
                if (v > 127) v = 127; \
                buffer.addEvent(createParamChange(channel, id, v), samplePos); \
            }

        // LFO
        CHECK_VAR(lfoRate, LFO_RATE, 127.0f);
        CHECK_VAR(lfoDelay, LFO_DELAY, 127.0f);
        
        // DCO
        CHECK_VAR(lfoToDCO, DCO_LFO, 127.0f);
        CHECK_VAR(pwmAmount, DCO_PWM, 127.0f);
        CHECK_VAR(noiseLevel, DCO_NOISE, 127.0f);
        CHECK_VAR(subOscLevel, DCO_SUB, 127.0f);
        
        // VCF
        CHECK_VAR(vcfFreq, VCF_FREQ, 127.0f);
        CHECK_VAR(resonance, VCF_RES, 127.0f);
        CHECK_VAR(envAmount, VCF_ENV, 127.0f);
        CHECK_VAR(lfoToVCF, VCF_LFO, 127.0f);
        CHECK_VAR(kybdTracking, VCF_KYBD, 127.0f);
        
        // VCA
        CHECK_VAR(vcaLevel, VCA_LEVEL, 127.0f);
        
        // ENV
        CHECK_VAR(attack, ENV_A, 127.0f);
        CHECK_VAR(decay, ENV_D, 127.0f);
        CHECK_VAR(sustain, ENV_S, 127.0f);
        CHECK_VAR(release, ENV_R, 127.0f);
        
        #undef CHECK_VAR
        
        // PACKED SWITCHES
        // We reconstruct the full bytes and see if they differ.
        
        // Switch 1: Chorus, HPF
        // HPF: 0-3 (Bits 0-1? Or 0-2? Juno HPF is 0(off), 1, 2, 3) 
        // Real Juno-106: HPF 0-3 maps to low bits.
        // Chorus: Off(0), I(1), II(2). Bits 4-6? 
        // 106 Service Manual: 
        // Bit 0,1: HPF (0-3)
        // Bit 4: Chorus 1
        // Bit 5: Chorus 2
        // Bit 6: Chorus? (Usually Ch1 | Ch2<<1)
        
        // [Hardware Authenticity] Switch 1: Chorus, Range, Pulse, Saw
        auto makeSw1 = [](const SynthParams& p) -> uint8_t {
            uint8_t b = 0;
            // Chorus (Bits 0-1)
            if (p.chorus1 || p.chorus2) b |= (1 << 0);
            if (p.chorus2) b |= (1 << 1);
            
            // Range (Bits 3-4)
            int hwRange = juce::jlimit(0, 2, (int)p.dcoRange);
            b |= (uint8_t)((hwRange & 0x03) << 3);
            
            if (p.pulseOn) b |= (1 << 5);
            if (p.sawOn)   b |= (1 << 6);
            return b;
        };

        // [Hardware Authenticity] Switch 2: PWM Mode, VCA Mode, Polarity, HPF
        auto makeSw2 = [](const SynthParams& p) -> uint8_t {
             uint8_t b = 0;
             if (p.pwmMode == 1)     b |= (1 << 0);
             if (p.vcaMode == 1)     b |= (1 << 1);
             if (p.vcfPolarity == 1) b |= (1 << 2);
             
             // HPF (Bits 3-4): Descending logic
             int hwHpf = 3 - juce::jlimit(0, 3, (int)p.hpfFreq);
             b |= (uint8_t)((hwHpf & 0x03) << 3);
             return b;
        };

        uint8_t oldSw1 = makeSw1(oldP);
        uint8_t newSw1 = makeSw1(newP);
        if (oldSw1 != newSw1) {
            buffer.addEvent(createParamChange(channel, SWITCHES_1, newSw1), samplePos);
        }

        uint8_t oldSw2 = makeSw2(oldP);
        uint8_t newSw2 = makeSw2(newP);
        if (oldSw2 != newSw2) {
             buffer.addEvent(createParamChange(channel, SWITCHES_2, newSw2), samplePos);
        }
    }
}

#include "JunoSysExEngine.h"

using namespace JunoSysEx;

void JunoSysExEngine::handleIncomingSysEx (const juce::MidiMessage& msg,
                                           SynthParams& params)
{
    if (msg.getRawDataSize() < 5) return;
    
    // [Fidelidad] Compatibility Check: Handle both Old and New Roland formats
    // Old: F0 41 <Type> <Channel> ...
    // New: F0 41 <DeviceID> <ModelID> ...
    
    int type = 0, ch = 0, p1 = 0, p2 = 0;
    uint8_t dumpData[18]; 
    
    if (! JunoSysEx::parseMessage (msg, type, ch, p1, p2, dumpData)) {
         return;
    }

    // Verify channel matches or it's Omni
    if (ch != (params.midiChannel - 1) && params.midiChannel != 0) {
        // ... (Optional: add strict channel filtering)
    }

    if (type == kMsgParamChange)
    {
        applyParamChange (p1, p2, params);
    }
    else if (type == kMsgPatchDump)
    {
        applyPatchDump (dumpData, params);
    }
}

juce::MidiMessage JunoSysExEngine::makeParamChange (int channel,
                                                    int paramId,
                                                    int value)
{
    return JunoSysEx::createParamChange (channel, paramId, value & 0x7F);
}

juce::MidiMessage JunoSysExEngine::makePatchDump (int channel,
                                                  const SynthParams& params)
{
    uint8_t body[16] {};

    body[0]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.lfoRate * 127.0f));
    body[1]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.lfoDelay * 127.0f));
    body[2]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.lfoToDCO * 127.0f));
    body[3]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.pwmAmount * 127.0f));
    body[4]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.noiseLevel * 127.0f));
    body[5]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.vcfFreq * 127.0f));
    body[6]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.resonance * 127.0f));
    body[7]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.envAmount * 127.0f));
    body[8]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.lfoToVCF * 127.0f));
    body[9]  = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.kybdTracking * 127.0f));
    body[10] = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.vcaLevel * 127.0f));
    body[11] = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.attack * 127.0f));
    body[12] = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.decay * 127.0f));
    body[13] = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.sustain * 127.0f));
    body[14] = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.release * 127.0f));
    body[15] = (uint8_t) juce::jlimit (0, 127, (int) std::round (params.subOscLevel * 127.0f));

    // [Hardware Authenticity] SW1 (Byte 20): Chorus, Range, Pulse, Saw
    uint8_t sw1 = 0;
    // Bit 0: Chorus Enable
    if (params.chorus1 || params.chorus2) sw1 |= (1 << 0);
    // Bit 1: Chorus Type (1=II, 0=I)
    if (params.chorus2) sw1 |= (1 << 1);
    
    // Bits 3-4: Range (0: 16', 1: 8', 2: 4')
    int hwRange = juce::jlimit(0, 2, params.dcoRange);
    sw1 |= (uint8_t)((hwRange & 0x03) << 3);
    
    // Bit 5: Pulse
    if (params.pulseOn) sw1 |= (1 << 5);
    // Bit 6: Saw
    if (params.sawOn)   sw1 |= (1 << 6);

    // [Hardware Authenticity] SW2 (Byte 21): PWM Mode, VCA Mode, Polarity, HPF
    uint8_t sw2 = 0;
    if (params.pwmMode == 1)     sw2 |= (1 << 0);
    if (params.vcaMode == 1)     sw2 |= (1 << 1);
    if (params.vcfPolarity == 1) sw2 |= (1 << 2);

    // HPF: Descending logic (3=Boost, 2=Flat, 1=225Hz, 0=450Hz)
    int hwHpf = 3 - juce::jlimit(0, 3, params.hpfFreq);
    sw2 |= (uint8_t)((hwHpf & 0x03) << 3);

    return JunoSysEx::createPatchDump (channel, body, sw1, sw2);
}

void JunoSysExEngine::applyParamChange (int paramId,
                                        int value7bit,
                                        SynthParams& params)
{
    const float norm = juce::jlimit (0.0f, 1.0f, value7bit / 127.0f);

    switch (paramId)
    {
        case LFO_RATE:   params.lfoRate = norm; break;
        case LFO_DELAY:  params.lfoDelay = norm; break;
        case DCO_LFO:    params.lfoToDCO = norm; break;
        case DCO_PWM:    params.pwmAmount = norm; break;
        case DCO_NOISE:  params.noiseLevel = norm; break;
        case VCF_FREQ:   params.vcfFreq = norm; break;
        case VCF_RES:    params.resonance = norm; break;
        case VCF_ENV:    params.envAmount = norm; break;
        case VCF_LFO:    params.lfoToVCF = norm; break;
        case VCF_KYBD:   params.kybdTracking = norm; break;
        case VCA_LEVEL:  params.vcaLevel = norm; break;
        case ENV_A:      params.attack = norm; break;
        case ENV_D:      params.decay = norm; break;
        case ENV_S:      params.sustain = norm; break;
        case ENV_R:      params.release = norm; break;
        case DCO_SUB:    params.subOscLevel = norm; break;

        case SWITCHES_1:
             {
                 bool cEnable = (value7bit & (1 << 0)) != 0;
                 bool cMode2  = (value7bit & (1 << 1)) != 0;
                 params.chorus1 = cEnable && !cMode2;
                 params.chorus2 = cEnable && cMode2;
                 
                 params.dcoRange = (value7bit >> 3) & 0x03;
                 params.pulseOn  = (value7bit & (1 << 5)) != 0;
                 params.sawOn    = (value7bit & (1 << 6)) != 0;
             }
             break;

        case SWITCHES_2:
             params.pwmMode     = (value7bit & (1 << 0)) ? 1 : 0;
             params.vcaMode     = (value7bit & (1 << 1)) ? 1 : 0;
             params.vcfPolarity = (value7bit & (1 << 2)) ? 1 : 0;
             // HPF: EngineVal = 3 - SysExVal
             params.hpfFreq     = 3 - ((value7bit >> 3) & 0x03);
            break;

        default:
            break;
    }
}

void JunoSysExEngine::applyPatchDump (const uint8_t* dumpData,
                                      SynthParams& params)
{
    auto v = [&dumpData] (int idx) -> float
    {
        return juce::jlimit (0.0f, 1.0f, dumpData[idx] / 127.0f);
    };

    params.lfoRate     = v (0);
    params.lfoDelay    = v (1);
    params.lfoToDCO    = v (2);
    params.pwmAmount   = v (3);
    params.noiseLevel  = v (4);
    params.vcfFreq     = v (5);
    params.resonance   = v (6);
    params.envAmount   = v (7);
    params.lfoToVCF    = v (8);
    params.kybdTracking = v (9);
    params.vcaLevel    = v (10);
    params.attack      = v (11);
    params.decay       = v (12);
    params.sustain     = v (13);
    params.release     = v (14);
    params.subOscLevel = v (15);

    const uint8_t sw1 = dumpData[16];
    const uint8_t sw2 = dumpData[17];

    // SW1 Parsing
    {
        bool cEnable = (sw1 & (1 << 0)) != 0;
        bool cMode2  = (sw1 & (1 << 1)) != 0;
        params.chorus1 = cEnable && !cMode2;
        params.chorus2 = cEnable && cMode2;
        
        params.dcoRange = (sw1 >> 3) & 0x03;
        params.pulseOn  = (sw1 & (1 << 5)) != 0;
        params.sawOn    = (sw1 & (1 << 6)) != 0;
    }

    // SW2 Parsing
    params.pwmMode     = (sw2 & (1 << 0)) ? 1 : 0;
    params.vcaMode     = (sw2 & (1 << 1)) ? 1 : 0;
    params.vcfPolarity = (sw2 & (1 << 2)) ? 1 : 0;
    params.hpfFreq     = 3 - ((sw2 >> 3) & 0x03);
}

