// ============================================================================
// JunoADSR Implementation
// Authentic Roland Juno-106 Envelope Reproduction
// ============================================================================

JunoADSR::JunoADSR()
{
    reset();
}

void JunoADSR::setSampleRate(double sr)
{
    if (sr > 0.0) {
        sampleRate = sr;
        calculateRates();
    }
}

void JunoADSR::reset()
{
    stage = Stage::Idle;
    currentValue = 0.0f;
}

void JunoADSR::setAttack(float seconds)
{
    attackTime = juce::jlimit(0.001f, 10.0f, seconds);
    calculateRates();
}

void JunoADSR::setDecay(float seconds)
{
    decayTime = juce::jlimit(0.001f, 10.0f, seconds);
    calculateRates();
}

void JunoADSR::setSustain(float level)
{
    sustainLevel = juce::jlimit(0.0f, 1.0f, level);
}

void JunoADSR::setRelease(float seconds)
{
    releaseTime = juce::jlimit(0.001f, 10.0f, seconds);
    calculateRates();
}

void JunoADSR::setGateMode(bool enabled)
{
    gateMode = enabled;
}

void JunoADSR::noteOn()
{
    stage = Stage::Attack;
    mcuUpdateCounter = 0; // [Fix] Start MCU update cycle immediately on Note On
}

void JunoADSR::noteOff()
{
    if (stage != Stage::Idle) {
        stage = Stage::Release;
    }
}

float JunoADSR::getNextSample()
{
    if (gateMode) {
         float target = (stage == Stage::Release || stage == Stage::Idle) ? 0.0f : 0.97f;
         // [Fidelity] Fast analog-style slew (~2ms) to prevent digital clicks
         currentValue += (target - currentValue) * 0.03f;

         // [Fix] Gate mode must also terminate to Stage::Idle to allow voice reuse
         if (stage == Stage::Release && currentValue < 0.001f) {
             currentValue = 0.0f;
             stage = Stage::Idle;
         }
    } else {
        // [Fidelidad] MCU Update Cycle (3ms ~ 132 samples @ 44.1k)
        if (--mcuUpdateCounter <= 0) {
        mcuUpdateCounter = mcuUpdateRateSamples;

        switch (stage)
        {
            case Stage::Attack:
            {
                // [Audit Compliance] VCF Overshoot emulation (Target > 1.0)
                // We target 1.08f to simulate the analog overshoot behavior commanded by the 8031.
                currentValue += attackRate * (1.08f - currentValue); 
                if (currentValue >= 1.0f) {
                    currentValue = 1.0f;
                    stage = Stage::Decay;
                }
                break;
            }
            
            case Stage::Decay:
            {
                // [Fidelity] Juno-106 "Shifted Space" logic:
                // Decay happens towards 0.0 in a space shifted by sustainLevel.
                float x = currentValue - sustainLevel;
                x *= decayRate; 
                currentValue = x + sustainLevel;

                if (std::abs(currentValue - sustainLevel) <= 0.001f) {
                    currentValue = sustainLevel;
                    stage = Stage::Sustain;
                }
                break;
            }
            
            case Stage::Sustain:
                // [Fidelity] In the Juno-106, Sustain changes are instantaneous 
                // but since we are digital, we ensure currentValue follows sustainLevel.
                currentValue = sustainLevel; 
                break;
            
            case Stage::Release:
            {
                // [Fidelity] Juno-106 "Shifted Space" logic:
                // Release happens towards 0.0 in a space shifted by 0.0.
                // This is effectively a decay towards 0.0.
                float x = currentValue; // No shift needed for target 0.0
                x *= releaseRate; 
                currentValue = x;

                if (currentValue < 0.0001f) { // [Fix] Lower threshold for high-precision release
                    currentValue = 0.0f;
                    stage = Stage::Idle;
                }
                break;
            }
            
            case Stage::Idle:
            default:
                break;
        }
    }
    }
    
    // [Fidelidad] 8-BIT DAC QUANTIZATION (256 steps)
    // The original 8031 MCU used an 8-bit DAC for envelope control.
    // 4-bit was too aggressive and killed low sustain levels.
    float quantized = std::floor(currentValue * 255.99f) / 255.0f;
    return quantized;
}

void JunoADSR::calculateRates()
{
    if (sampleRate <= 0.0) return;
    
    // Recalculate MCU samples
    mcuUpdateRateSamples = (int)(0.003 * sampleRate); // 3ms
    if (mcuUpdateRateSamples < 1) mcuUpdateRateSamples = 1;

    auto getAuthenticRate = [&](float tau, bool isAttack) -> float {
        float updateInterval = (float)mcuUpdateRateSamples;
        float sr = (float)sampleRate;
        
        if (isAttack) {
             // Attack: Logarithmic approach to target (Target > 1.0 for overshoot)
             // Rate is adjusted so it reaches 1.0 in approx 'tau' seconds
             return 1.0f - std::exp(-updateInterval / (tau * sr * 0.35f));
        } else {
             // Decay/Release: Exponential to target
             // Rate is adjusted so it reaches 37% in approx 'tau' seconds
             return std::exp(-updateInterval / (tau * sr));
        }
    };

    attackRate = getAuthenticRate(attackTime, true); 
    decayRate = getAuthenticRate(decayTime, false);
    releaseRate = getAuthenticRate(releaseTime, false);
}

// Source/Synth/JunoADSR.h
#pragma once

#include <JuceHeader.h>

/**
 * JunoADSR - Authentic Juno-106 ADSR Envelope
 * 
 * CHARACTERISTICS:
 * - Exponential Curves - Matches the Juno-106's software-generated envelopes.
 * - Software Snappiness: The original Juno-106 envelopes were generated by the on-board MCU,
 *   providing distinct exponential shapes that are "snappy" but musically smooth.
 * - GATE mode support: When the VCA is in GATE mode, the envelope is bypassed/simplified.
 * 
 * IMPLEMENTATION:
 * - State machine: Idle, Attack, Decay, Sustain, Release.
 * - Attack is 1 - exp(-t/tau) [Logarithmic rise].
 * - Decay/Release are exp(-t/tau) [Exponential fall].
 */
class JunoADSR {
public:
    enum class Stage {
        Idle,
        Attack,
        Decay,
        Sustain,
        Release
    };
    
    JunoADSR();
    
    // Setup
    void setSampleRate(double sampleRate);
    void reset();
    
    // Parameters (seconds)
    void setAttack(float seconds);
    void setDecay(float seconds);
    void setSustain(float level);      // 0-1
    void setRelease(float seconds);
    void setGateMode(bool enabled);    // ENV button
    
    // Lifecycle
    void noteOn();
    void noteOff();
    
    // Processing
    float getNextSample();
    bool isActive() const { return stage != Stage::Idle; }
    
    Stage getCurrentStage() const { return stage; }
    float getCurrentValue() const { return currentValue; }
    
private:
    double sampleRate = 44100.0;
    
    // Parameters
    float attackTime = 0.01f;      // seconds
    float decayTime = 0.3f;        // seconds
    float sustainLevel = 0.7f;     // 0-1
    float releaseTime = 0.5f;      // seconds
    bool gateMode = false;         // ENV button state
    
    // Linear rates (per-sample increment/decrement)
    float attackRate = 0.0f;
    float decayRate = 0.0f;
    float releaseRate = 0.0f;
    
    // State
    Stage stage = Stage::Idle;
    float currentValue = 0.0f;
    
    // [Fidelidad] MCU Emulation
    int mcuUpdateCounter = 0;
    int mcuUpdateRateSamples = 0;
    
    // Helper
    void calculateRates();
};

