}

.sq.patch-blue[data-active="true"],
.sq.patch-blue.pushed {
    background-image: url('../button_blue_on.png');
}

.sq.grey {
    background: url('../button_grey_off.png') no-repeat center center;
    background-size: contain;
}

.sq.grey[data-active="true"],
.sq.grey.pushed {
