}

.settings-content {
    display: grid;
    grid-template-columns: 1fr 1fr; /* Two columns */
    gap: 20px;
    max-height: 500px;
    overflow-y: auto;
    padding-right: 5px;
}

.setting-row {
    display: grid;
    grid-template-columns: 120px 1fr 50px; /* Adjusted for narrower columns */
    align-items: center;
    gap: 15px;
    margin-bottom: 0px; /* Gap handled by grid */
    padding: 12px;
    background: rgba(255,255,255,0.02);
    border: 1px solid rgba(255,255,255,0.05);
