    bottom: 8px;
    width: 4px;
    left: 14px;
    background: transparent;
}

.handle {
    position: absolute;
    width: 32px;
    height: 16px;
    left: 0;
    background: url('../slider_cap.png') no-repeat center center;
    background-size: contain;
    pointer-events: none;
